#include <stdio.h>
#include <string.h>

int sumOfDigits(int n) {
    int sum = 0;
    while (n > 0) {
        sum += n % 10;
        n /= 10;
    }
    return sum;
}

int main() {
    int N;
    scanf("%d", &N);
    int count = 0;
    for (int X = 1; X <= N; X++) {
        int sumX = sumOfDigits(X);
        int sumSumX = sumOfDigits(sumX);
        if (X + sumX + sumSumX == N) {
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

